"""Render Jinja templates and write generated files."""

from __future__ import annotations

from pathlib import Path

import jinja2

from scripts.codegen.plan import (
    ModuleContext,
    PackContext,
    arg_python_type,
    build_module_context,
    qp_kwarg,
    qp_type,
)

TEMPLATE_DIR = Path(__file__).resolve().parent / "templates"

GENERATED_HEADER = (
    "# This file is generated by scripts/codegen from\n"
    "# catalog/curated_tools/{id}.yml. Do not edit by hand.\n"
    "# Regenerate with: make codegen\n\n"
)
GENERATED_HEADER_PACK = (
    "# This file is generated by scripts/codegen from\n"
    "# catalog/curated_tools/_packs/{id}.yml plus all per-resource\n"
    "# descriptors in the same pack. Do not edit by hand.\n"
    "# Regenerate with: make codegen\n\n"
)


def make_environment() -> jinja2.Environment:
    """Build a Jinja environment with codegen helpers exposed."""

    # autoescape=False is safe here: we render Python source, not HTML.
    env = jinja2.Environment(
        loader=jinja2.FileSystemLoader(TEMPLATE_DIR),
        autoescape=False,  # noqa: S701 (Python-source codegen, not HTML)
        trim_blocks=False,
        lstrip_blocks=False,
        keep_trailing_newline=False,
    )
    # Jinja's `globals` dict is typed for built-in helpers; assigning plain
    # callables is supported at runtime but not in pyright's stub.
    env.globals["qp_type"] = qp_type  # pyright: ignore[reportArgumentType]
    env.globals["qp_kwarg"] = qp_kwarg  # pyright: ignore[reportArgumentType]
    env.globals["arg_python_type"] = arg_python_type  # pyright: ignore[reportArgumentType]
    # python_literal filter: emit a Python-source-compatible literal of a
    # value (dict / list / scalars). Distinct from `tojson` which emits
    # JSON syntax (lowercase true/false/null) — generated code needs
    # Python literals (True / False / None).
    env.filters["python_literal"] = repr  # pyright: ignore[reportArgumentType]
    return env


def render_module(env: jinja2.Environment, ctx: ModuleContext) -> str:
    """Render `_generated_<id>.py` for one descriptor."""

    template = env.get_template("tool_module.py.j2")
    body = template.render(**ctx.as_jinja_context())
    return GENERATED_HEADER.format(id=ctx.descriptor.id) + body


def render_pack_init(env: jinja2.Environment, ctx: PackContext) -> str:
    """Render the pack `__init__.py`."""

    template = env.get_template("pack_init.py.j2")
    body = template.render(**ctx.as_jinja_context())
    return GENERATED_HEADER_PACK.format(id=ctx.pack.id) + body


def emit_pack(
    env: jinja2.Environment,
    pack_ctx: PackContext,
    src_root: Path,
) -> list[Path]:
    """Emit every generated file for one pack. Returns written paths."""

    pack_dir = src_root / "rancher_mcp" / "tools" / pack_ctx.pack.id
    pack_dir.mkdir(parents=True, exist_ok=True)

    written: list[Path] = []

    for descriptor in pack_ctx.descriptors:
        module_ctx = build_module_context(descriptor)
        body = render_module(env, module_ctx)
        path = pack_dir / f"_generated_{descriptor.id}.py"
        path.write_text(body, encoding="utf-8")
        written.append(path)

    init_body = render_pack_init(env, pack_ctx)
    init_path = pack_dir / "__init__.py"
    init_path.write_text(init_body, encoding="utf-8")
    written.append(init_path)

    return written
